import{_ as l,W as d,X as c,Y as o,Z as e,$ as a,a0 as s,a1 as i,D as t}from"./framework-c9619a7b.js";const p={},r=i('<h1 id="抓包工具" tabindex="-1"><a class="header-anchor" href="#抓包工具" aria-hidden="true">#</a> 抓包工具</h1><h2 id="tcpdump" tabindex="-1"><a class="header-anchor" href="#tcpdump" aria-hidden="true">#</a> tcpdump</h2><p>命令格式：</p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/88362912bab78d3461107e1ac1594822.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>常用参数：</p><ul><li><code>-i</code>：指定网卡接口，<code>-i any</code>可以使用所有接口</li><li><code>-c</code>: 指定抓包数量</li><li><code>-nn</code>: 不解析主机地址和端口号为名字</li><li><code>-S</code>: 打印绝对TCP序列号，而不是相对序列号</li><li><code>-X</code>: 以以hex和ASCII形式打印数据包内容</li><li><code>-w</code>: 将结果写入文件，通常后缀为<code>.pcap</code></li><li><code>-D</code>: 查看拥有的网络接口</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/09bb19cf68d7756dda62960a1946fa0a.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure>',7),m=e("p",null,"表达式语法：",-1),g={href:"https://mp.weixin.qq.com/s?__biz=Mzg3MjU3NzU1OA==&mid=2247496415&idx=1&sn=cb549cd19397881dd7035f234c36fc33&chksm=ceef9da6f99814b0d6c8bcf60ed161cb01fd03b11a42be7653e51a6d77b027b7cedfb29c6137&mpshare=1&scene=1&srcid=0912qdDeHqFWxYSm3qav86RI&sharer_sharetime=1662960495870&sharer_shareid=b44ebbe82718b61b6a9fa0be4bb87fab#rd",target:"_blank",rel:"noopener noreferrer"},u=i(`<figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/435c38a6e33ddfa17d6f629be7a6847b.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>抓包结果格式：</p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/2e50d419dbace6b9a615b175c06dfe92.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>TCP标志位介绍：</p><ul><li><p><code>[S]</code> : SYN（开始连接）</p></li><li><p><code>[P]</code> : PSH（推送数据）</p></li><li><p><code>[F]</code> : FIN （结束连接）</p></li><li><p><code>[R]</code> : RST（重置连接）</p></li><li><p><code>[.]</code> : 没有 Flag，由于除了 SYN 包外所有的数据包都有ACK，所以一般这个标志也可表示 ACK</p></li></ul><p><strong>使用举例：</strong></p><ul><li>根据主机IP过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>tcpdump <span class="token function">host</span> <span class="token number">192.168</span>.10.100
tcpdump src <span class="token function">host</span> <span class="token number">192.168</span>.10.100
tcpdump dst <span class="token function">host</span> <span class="token number">192.168</span>.10.200
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>根据网段过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>tcpdump net <span class="token number">192.168</span>.10.0/24
tcpdump src net <span class="token number">192.168</span>.10.0/24
tcpdump dst net <span class="token number">192.168</span>.10.0/24
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>根据端口过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 单一端口</span>
tcpdump port <span class="token number">8088</span>
tcpdump src port <span class="token number">8088</span>
tcpdump dst port <span class="token number">8088</span>

<span class="token comment"># 端口范围</span>
tcpdump portrange <span class="token number">8000</span>-8080
tcpdump src portrange <span class="token number">8000</span>-8080
tcpdump dst portrange <span class="token number">8000</span>-8080
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>根据协议过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>tcpdump icmp
tcpdump <span class="token string">&#39;ip proto tcp&#39;</span>
tcpdump <span class="token string">&#39;ip6 proto tcp&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>组合过滤</li></ul><p title="相关信息">:::info</p><ol><li><p>逻辑语句：<code>and</code>, <code>or</code>, <code>not</code> 或 <code>&amp;&amp;</code>, <code>||</code>, <code>!</code></p></li><li><p>判断语句：<code>=</code>, <code>==</code>, <code>!=</code></p></li></ol><p>内置变量：</p><ul><li><code>if</code>: 网卡接口名</li><li><code>proc</code>: 进程名</li><li><code>pid</code>: 进程id</li><li><code>dir</code>: 方向</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 过滤来自进程名为 nc 发出的流经 en0 网卡的数据包，或者不流经 en0 的入方向数据包</span>
tcpdump <span class="token string">&quot;( if=en0 and proc=nc ) || (if != en0 and dir=in)&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>:::</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># find all traffic from 10.5.2.3 going to any host on port 3389</span>
tcpdump <span class="token parameter variable">-nnvvS</span> src <span class="token number">10.5</span>.2.3 and dst port <span class="token number">3389</span>

<span class="token comment"># look for all traffic coming from 192.168.x.x and going to the 10.x or 172.16.x.x networks</span>
tcpdump <span class="token parameter variable">-nvX</span> src net <span class="token number">192.168</span>.0.0/16 and dst net <span class="token number">10.0</span>.0.0/8 or <span class="token number">172.16</span>.0.0/16

<span class="token comment"># look for all traffic going to 192.168.0.2 that is not ICMP</span>
tcpdump dst <span class="token number">192.168</span>.0.2 and src net and not icmp

<span class="token comment"># look for all traffic from a host that isn’t SSH traffic</span>
tcpdump <span class="token parameter variable">-vv</span> src mars and not dst port <span class="token number">22</span>

tcpdump <span class="token string">&#39;src 10.0.2.4 and (dst port 3389 or 22)&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>根据标志位过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 指定标志位</span>
tcpdump <span class="token string">&#39;tcp[13] &amp; 2!=0&#39;</span>
tcpdump <span class="token string">&#39;tcp[tcpflags] == tcp-syn&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="wireshark" tabindex="-1"><a class="header-anchor" href="#wireshark" aria-hidden="true">#</a> Wireshark</h2><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/569487695f17b27574e451195f071e11.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p><strong>1. 捕获过滤表达式：</strong><br> 语法与<code>tcpdump</code>类似。先设定条件再进行抓包。</p><p><strong>2. 显示过滤表达式：</strong><br> 在抓完包后根据设定条件筛选感兴趣的包。</p><ul><li>根据ip过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>ip.src <span class="token operator">==</span> <span class="token number">192.168</span>.0.1
ip.dst <span class="token operator">==</span> <span class="token number">192.168</span>.0.1
ip.addr <span class="token operator">==</span> <span class="token number">192.168</span>.0.1
<span class="token operator">!</span><span class="token punctuation">(</span>ip.addr <span class="token operator">==</span> <span class="token number">192.168</span>.0.1<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>根据网段过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>根据端口过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>tcp.port <span class="token operator">==</span> <span class="token number">80</span>
udp.port <span class="token operator">&gt;=</span> <span class="token number">2048</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>根据协议过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>http
http or telnet
not arp <span class="token comment"># 或!arp</span>

<span class="token comment"># 根据标志位过滤</span>
<span class="token assign-left variable">tcp.flags.syn</span><span class="token operator">==</span><span class="token number">1</span>
tcp/flags.rst<span class="token operator">==</span><span class="token number">1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>根据长度过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>udp.length <span class="token operator">&lt;</span> <span class="token number">20</span>   
http.content_length <span class="token operator">&lt;=</span><span class="token number">30</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>根据内容过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>http.request.uri matches <span class="token string">&quot;user&quot;</span> 
http.request.uri contains <span class="token string">&quot;User&quot;</span>
<span class="token assign-left variable">http.host</span><span class="token operator">==</span>baidu.com
http.host contains <span class="token string">&quot;baidu&quot;</span>
http.content_type <span class="token operator">==</span><span class="token string">&quot;text/html&quot;</span>
<span class="token assign-left variable">http.request.method</span><span class="token operator">==</span><span class="token string">&quot;POST&quot;</span>
<span class="token assign-left variable">http.response.code</span><span class="token operator">==</span><span class="token number">302</span>
http.cookie contains <span class="token string">&quot;userid&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>组合过滤</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">ip.addr</span><span class="token operator">==</span><span class="token number">192.168</span>.2.121 <span class="token operator">&amp;&amp;</span> <span class="token assign-left variable">tcp.port</span><span class="token operator">==</span><span class="token number">10080</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p title="显示绝对序列号">:::tip</p><p><code>编辑&gt;首选项&gt;Protocols&gt;TCP</code></p><p><img src="https://minio.kevin2li.top/image-bed/vanblog/img/69aa123857090b17ea8e40d9ccda1b51.image.png" alt="image.png" loading="lazy"> :::</p>`,45),b={href:"https://www.comparitech.com/net-admin/decrypt-ssl-with-wireshark/",target:"_blank",rel:"noopener noreferrer"},v=i(`<ol><li>设置系统环境变量<code>SSLKEYLOGFILE</code></li></ol><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/de1aa7f50fc53f27511095a2204b25aa.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><ol start="2"><li>设置Wireshark的pre master secret。</li></ol><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/1e174aa2718e74c62702d7ad7fbb193a.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><ol start="3"><li><p>使用浏览器访问https网站<br> 注意：目前火狐浏览器和Chrome浏览器支持，其他浏览器不一定支持。</p></li><li><p>抓包</p></li></ol><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/79b9183ee45494f84204fb25b6e9c5d0.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>:::</p><h1 id="tcp协议格式" tabindex="-1"><a class="header-anchor" href="#tcp协议格式" aria-hidden="true">#</a> TCP协议格式</h1><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/739ff0bf9f06e941369bbe3cc3a8934f.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p><strong>字段说明</strong>：</p><ul><li><code>源端口</code>：2字节。</li><li><code>目的端口</code>: 2字节。</li><li><code>序号</code>: 本报文段所发送的数据的第一个字节的序号。<code>下一个报文段的序号=当前报文段序号+当前报文段数据长度</code>。</li><li><code>确认号</code>: 期望收到对方下一个报文段的第一个数据节的序号。 <code>确认号=接收报文段序号+接收报文段数据长度</code>。</li><li><code>数据偏移</code>：反映了TCP报文段的首部长度，含义为数据起始位置相对于TCP报文起始位置的距离。单位为4字节，说明报文首部长度最大为15*4=60字节。</li><li><code>保留</code>: 6位，暂时不用，置为零。</li><li><code>控制位</code>: <ul><li><code>URG</code>: 紧急位，告诉系统此报文段含有紧急数据需尽快传送，而不要按原来排队顺序传送。配合后面<code>紧急指针</code>一起使用。</li><li><code>ACK</code>：确认位，在连接建立后所有传送的报文段都必须把 ACK 置 1。</li><li><code>PSH</code>: 推送位，当该位置1时，发送方立即发送，接收方立即向上交付，而不再等缓存填满再交付。</li><li><code>RST</code>: 重置位，表明TCP连接出现严重差错，需要释放连接重新建立。</li><li><code>SYN</code>: 同步位，在建立连接时用来同步序号。</li><li><code>FIN</code>: 终止位，在关闭连接时用到。</li></ul></li><li><code>窗口</code>: 接收窗口大小，告诉发送方自己目前允许对方发送的数据量，单位为字节，经常动态变化。</li><li><code>检验和</code>: 检验范围包括首部和数据两部分。</li><li><code>紧急指针</code>: 指出本报文段紧急数据的字节数，紧急数据后为普通数据。</li><li><code>选项</code>: 长度可变，最大为40字节。</li></ul><h1 id="ip协议格式" tabindex="-1"><a class="header-anchor" href="#ip协议格式" aria-hidden="true">#</a> IP协议格式</h1><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/4d4132b0beb25a3a27226660db91c937.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p><strong>字段说明</strong>：</p><ul><li><code>版本</code>：IP协议版本。</li><li><code>首部长度</code>: 占4位，可表示数据范围为0~15，单位为4字节，表明首部长度最大为15*4=60字节。</li><li><code>区分服务</code>: 暂时不用。</li><li><code>总长度</code>: 首部和数据之和的长度。最大为65535字节。实际上不能超过MTU(以太网规定MTU为1500字节)，否则会进行分片。</li><li><code>标识</code>: 数据报的编号，当产生分片时，利用该字段便于将属于同一数据包的各个分片重新组装。</li><li><code>标志</code>: 标志位，占3位，只用到2位： <ul><li><code>MF</code>: <code>MF=1</code>表示后面还有分片。</li><li><code>DF</code>: <code>DF=1</code>表示不能分片，只有为0时才允许分片。</li></ul></li><li><code>片偏移</code>: 指出该分片在原始分组数据字段的起点的相对偏移位置，单位为8字节。</li><li><code>生存时间</code>: <code>TTL</code>(Time To Live)，至多允许的跳数。</li><li><code>协议</code>: 数据字段部分使用的协议。</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/132f33c3f97fed92a874c5f018083977.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><ul><li><code>首部检验和</code>: 只检验首部，不包括数据部分。</li><li><code>源地址</code>: 4字节</li><li><code>目标地址</code>：4字节</li></ul><h1 id="实战分析" tabindex="-1"><a class="header-anchor" href="#实战分析" aria-hidden="true">#</a> 实战分析</h1><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/6c9444675ce0d35d5e97b283bf9e33b3.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><ol><li>在机器B上搭建一个http服务</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>python <span class="token parameter variable">-m</span> http.server <span class="token number">9099</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="2"><li>在机器A上使用tcpdump准备抓包</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> tcpdump <span class="token parameter variable">-nnS</span> <span class="token parameter variable">-i</span> wlx90de8095c21f <span class="token function">host</span> <span class="token number">192.168</span>.2.121 and port <span class="token number">9099</span> <span class="token parameter variable">-w</span> test.pcap
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="4"><li>在机器A上访问机器B上的http服务</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">curl</span> http://192.168.2.121:9099
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ol start="3"><li>将抓到的包文件<code>test.cap</code>导入wireshark分析</li></ol><p>流量图分析：</p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/1494605f76e3535f517d697f78b64441.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/634d89585bfa16c03eec0fefbd0b8ecd.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>可以看到，前三个包是建立tcp连接的过程，最后两个包是关闭tcp连接的过程。</p><h1 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h1>`,31),h={href:"https://mp.weixin.qq.com/s?__biz=MzI4Njg5MDA5NA==&mid=2247490413&idx=3&sn=0781cc043cdf46990e1fe7f49ef175d8&chksm=ebd75a6cdca0d37a12cf8239c7701d562aaf9b2bf6a77a5769df8def2ef6233bcd0bbd5708cf&mpshare=1&scene=1&srcid=0420lU6NUxp6kvWCBheOci0A&sharer_sharetime=1681952381109&sharer_shareid=b44ebbe82718b61b6a9fa0be4bb87fab#rd",target:"_blank",rel:"noopener noreferrer"};function f(k,x){const n=t("ExternalLinkIcon");return d(),c("div",null,[r,o(" more "),m,e("blockquote",null,[e("p",null,[a("参考："),e("a",g,[a("肝了三天，万字长文教你玩转 tcpdump，从此抓包不用愁"),s(n)])])]),u,e("p",null,[a(':::tip{title="抓https网络包"} 参考：'),e("a",b,[a("https://www.comparitech.com/net-admin/decrypt-ssl-with-wireshark/"),s(n)])]),v,e("ol",null,[e("li",null,[e("a",h,[a("java3y-实战-图解TCP"),s(n)])])])])}const q=l(p,[["render",f],["__file","TCP协议教程.html.vue"]]);export{q as default};
